parameters.jsCode:
const materials = $input.all();

const map = {};
const titles = {};
const lines = [];

materials.forEach((item, index) => {
  const number = (index + 1).toString();

  map[number] = item.json.id;
  titles[number] = item.json.title;

  lines.push(`${number}. ${item.json.title}`);
});

return [
  {
    json: {
      message:
`📚 Choose a topic:

${lines.join('\n')}

👉 Reply with a number`,
      state: "select_topic",
      data: {
        map,
        titles
      }
    }
  }
];

const userInput = $('Switch').first().json.command.trim();

const map = $input.first().json.data.map;

const selectedId = map[userInput];

if (!selectedId) {
  return [
    {
      json: {
        error: true,
        message: "Invalid topic selection."
      }
    }
  ];
}

return [
  {
    json: {
      selectedId
    }
  }
];

const session = $input.first().json.data;

const index = session.currentQuestion || 0;

const question = session.quiz.questions[index];

return [
  {
    json: {
      chatId: $input.first().json.user_id,
      text:
`❓ Question ${index + 1}/${session.quiz.questions.length}

${question.question}

A) ${question.options.A}
B) ${question.options.B}
C) ${question.options.C}
D) ${question.options.D}`,

      reply_markup: {
        inline_keyboard: [
          [
            { text: "A", callback_data: "A" },
            { text: "B", callback_data: "B" }
          ],
          [
            { text: "C", callback_data: "C" },
            { text: "D", callback_data: "D" }
          ]
        ]
      }
    }
  }
];

const callback = $json.callback_query;

return {
  json: {
    chatId: callback.message.chat.id,
    userId: callback.from.id,
    answer: callback.data
  }
};

const inputs = $input.all().filter(i => i && i.json);

// 1. callback input
const callbackItem = inputs.find(i =>
  i.json.callback_query ||
  i.json.answer ||
  i.json.data
);

if (!callbackItem) {
  throw new Error("No callback input found");
}

const callback = callbackItem.json;

// 2. session input (Supabase row)
const sessionItem = inputs.find(i =>
  i.json.data && i.json.data.quiz
);

if (!sessionItem) {
  throw new Error("No session found");
}

const session = sessionItem.json.data;

// 3. answer extraction (Telegram-safe)
const answer = $('Code in JavaScript1').first().json.answer

// 4. current state
const index = session.currentQuestion || 0;
const question = session.quiz.questions[index];

// 5. validate
const isCorrect =
  String(answer).trim() === String(question.correctAnswer).trim();

let score = session.score || 0;
if (isCorrect) score++;

const nextIndex = index + 1;
const isLastQuestion = nextIndex >= session.quiz.questions.length;

// 6. output
return [
  {
    json: {
      chatId:
        callback.chatId ||
        callback.callback_query?.message?.chat?.id,

      isCorrect,
      correctAnswer: question.correctAnswer,
      explanation: question.explanation,

      nextIndex,
      score,

      quiz: session.quiz,
      isLastQuestion
    }
  }
];

