parameters.jsCode:
const session = $('Update a row1').first().json.data;

const index = session.currentQuestion;

const question = session.quiz.questions[index];

return [
  {
    json: {
      chatId: $('Update a row1').first().json.user_id,

      text:
`❓ Question ${index + 1}/${session.quiz.questions.length}

${question.question}

A) ${question.options.A}
B) ${question.options.B}
C) ${question.options.C}
D) ${question.options.D}`,

      reply_markup: {
        inline_keyboard: [
          [
            { text: "A", callback_data: "A" },
            { text: "B", callback_data: "B" }
          ],
          [
            { text: "C", callback_data: "C" },
            { text: "D", callback_data: "D" }
          ]
        ]
      }
    }
  }
];

const session = $input.first().json;

const answers = session.data?.answers || [];

function cleanQuestion(text) {
  return (text || "")
    .replace(/This message was sent automatically with n8n.*$/g, "")
    .replace(/❓ Question \d+\/\d+/g, "")
    // REMOVE A) B) C) D) OPTIONS
    .replace(/\n?\s*[A-D]\)\s.*(\n|$)/g, "")
    .trim();
}

const results = answers.map((a) => ({
  question: cleanQuestion(a.question),
  isCorrect: a.isCorrect,
  userAnswer: a.userAnswer,
  correctAnswer: a.correctAnswer,
  explanation: a.explanation
}));

const correctCount = results.filter(r => r.isCorrect).length;
const total = results.length;
const scorePercent = Math.round((correctCount / total) * 100);

const messageLines = [];

messageLines.push(`🎉 Quiz completed!\n`);
messageLines.push(`Score: ${scorePercent}% (${correctCount}/${total} correct)\n`);

results.forEach((r, idx) => {

  // QUESTION FIRST
  messageLines.push(`❓ Q${idx + 1}:`);
  messageLines.push(r.question);
  messageLines.push("");

  if (r.isCorrect) {
    // ONLY QUESTION + RESULT
    messageLines.push(`✅ Correct\n`);
  } else {
    // FULL BREAKDOWN
    messageLines.push(
      `❌ Incorrect\n` +
      `Your answer: ${r.userAnswer}\n` +
      `Correct answer: ${r.correctAnswer}\n` +
      `Explanation: ${r.explanation}\n`
    );
  }
});

return [
  {
    json: {
      chatId: session.user_id,
      scorePercent,
      correctCount,
      total,
      message: messageLines.join("\n")
    }
  }
];
